// ApiService.kt
import retrofit2.Call
import retrofit2.http.GET
import retrofit2.http.Header

interface ApiService {
    @GET("users")
    fun getUserProfiles(@Header("Authorization") token: String): Call<List<UserProfile>>
}

// UserProfile.kt
data class UserProfile(val id: String, val name: String, val email: String)

// ApiClient.kt
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

object ApiClient {
    private const val DEV_BASE_URL = "https://dev.api.example.com/"
    private const val STAGING_BASE_URL = "https://staging.api.example.com/"
    private const val PROD_BASE_URL = "https://api.example.com/"
    
    private fun getBaseUrl(): String {
        // Logic to determine environment
        return when (BuildConfig.BUILD_TYPE) {
            "debug" -> DEV_BASE_URL
            "staging" -> STAGING_BASE_URL
            else -> PROD_BASE_URL
        }
    }
    
    private fun createOkHttpClient(): OkHttpClient {
        return OkHttpClient.Builder().build()
    }

    val apiService: ApiService by lazy {
        Retrofit.Builder()
            .baseUrl(getBaseUrl())
            .client(createOkHttpClient())
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(ApiService::class.java)
    }
}

// Repository.kt
class UserRepository {
    fun fetchUserProfiles(token: String, callback: (List<UserProfile>?, Throwable?) -> Unit) {
        val call = ApiClient.apiService.getUserProfiles("Bearer $token")
        call.enqueue(object : retrofit2.Callback<List<UserProfile>> {
            override fun onResponse(
                call: retrofit2.Call<List<UserProfile>>,
                response: retrofit2.Response<List<UserProfile>>
            ) {
                if (response.isSuccessful) {
                    callback(response.body(), null)
                } else {
                    callback(null, Throwable(response.message()))
                }
            }

            override fun onFailure(call: retrofit2.Call<List<UserProfile>>, t: Throwable) {
                callback(null, t)
            }
        })
    }
}